head.script:
// 컨테이너 목록 상세 화면
// '▶ 조회조건
//     오더번호 : DC20604240061
// CC22005060090
// DC12507280016 
// FC42604130009
// BC32601280005


// ▶ 기타 내용
//     부모 화면 수입일반 오더(C2)
//     (tn_201_02_03b.jsp) 에서 [컨테이너상세] 버튼 클릭 시 오픈 (조회조건 - 오더번호 : DC20604240061)


scwin.onpageload = function () {

    scwin.memJson = $c.data.getMemInfo();
    scwin.lobranCd = scwin.memJson.lobranCd;// 점소명
    //다른화면에서 넘어오는 경우
    scwin.odrNo = $c.data.getParameter("odrNo") == null ? "" : $c.data.getParameter("odrNo");			// 오더번호
    scwin.odrKndCd = $c.data.getParameter("odrKndCd") == null ? "" : $c.data.getParameter("odrKndCd");	// 오더종류
    scwin.type = $c.data.getParameter("type") == null ? "" : $c.data.getParameter("type");			    // type
    scwin.linkPage = $c.data.getParameter("linkPage") == null ? "" : $c.data.getParameter("linkPage");	// 링크페이지 종류
    scwin.odrCopy = $c.data.getParameter("odrCopy") == null ? "" : $c.data.getParameter("odrCopy");		// 웹오더요청번호

    // let odrKndCd		= "";	//오더종류코드
    scwin.impExpClsCd = "";	//수출입내수구분코드
    scwin.mgntTrgtClntYn = 0; 	//거래처 관리대상여부
    scwin.retrieveYn = "N";	//조회여부
    scwin.excelUploadYn = 0;	//EXCEL UPLOAD (C3) 여부
};

// asis tobe 타이틀 상이할 경우 변경하는 함수.
scwin.popTitleCh = function () {
    $c.data.setPopupTitle("컨테이너 목록 상세 화면");
};

// UDC에 값 세팅 방법
// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function () {
    console.log("----------- onUdcCompleted");
    const codeOptions = [
        { grpCd: "SD133", compID: "gr_cntrInfo:offRtrnClsCd" },
        { grpCd: "SD102", compID: "gr_cntrInfo:cntrWtCondCd" },
        { grpCd: "SD165", compID: "gr_cntrInfo:cntrWrkClsCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_dsOrderSearchHeader();
    $c.gus.cfDisableObjects([tbl_odrInfoArea, tbl_rmk, tbl_odrInfoArea2]);
    $c.gus.cfDisableObjects([btn_saveM, btn_saveD, btn_deleteD]);

    gr_cntrInfo.setReadOnly("grid", true); // gr_cntrInfo.Editable = false;

    // todo - 맞는지 모르겠음
    if (scwin.odrNo != '') {
        ed_odrNo.setValue(scwin.odrNo);
        ds_cndOdrNo.set("odrNo", scwin.odrNo); // asis와 맞추기위해 추가함
        scwin.f_Retrieve();
    }
};

scwin.f_dsOrderSearchHeader = function () {
    ds_cndOdrNo.set("odrNo", "");
    // ds_cndOdrNo.set("odrNo", scwin.odrNo);
}

scwin.f_Retrieve = async function () {
    ds_cntrCnt.setEmptyValue(); // ds_cntrCnt.ClearData();
    ds_cntrCntCrossTab.removeAll(); // ds_cntrCntCrossTab.ClearData();
    ds_cntrInfo.removeAll();

    await scwin.submitExcute(sbm_retrieve);

}


//마스터 저장
scwin.f_updateM = function () {
    $c.gus.cfEnableObj(ta_rmk2, true);
    $c.gus.cfEnableObj(ed_dptOprCd, true);
    $c.gus.cfEnableObj(ed_dptTmlVsslPortcnt, true);
    $c.gus.cfEnableObj(ed_arvOprCd, true);
    $c.gus.cfEnableObj(ed_arvTmlVsslPortcnt, true);
    $c.gus.cfEnableObj(ed_oprBlNo, true);
    $c.gus.cfEnableObj(ed_oprDoNo, true);
    $c.gus.cfEnableObj(lc_oprImpexpClsCd, true);
    if (ed_ctrtClntNo.getValue() == "278038") {  // 278038 (주)판토스
        $c.gus.cfEnableObj(lc_fwdCd, true);
    } else {
        $c.gus.cfEnableObj(lc_fwdCd, false);
    }
    $c.gus.cfEnableObjects([btn_saveM]);
    $c.gus.cfDisableObjects([btn_updateM]);
}


scwin.f_saveM = async function () {

    let rawData = dma_odrInfo.getJSON();
    rawData.dptOprCd = ed_dptOprCd.getValue();
    rawData.dptTmlVsslPortcnt = ed_dptTmlVsslPortcnt.getValue();
    rawData.arvOprCd = ed_arvOprCd.getValue();
    rawData.arvTmlVsslPortcnt = ed_arvTmlVsslPortcnt.getValue();
    rawData.oprBlNo = ed_oprBlNo.getValue();
    rawData.oprDoNo = ed_oprDoNo.getValue();
    rawData.oprImpexpClsCd = lc_oprImpexpClsCd.getValue();
    rawData.fwdCd = lc_fwdCd.getValue();

    ds_odrInfo.setRowJSON(0, rawData, true);

    if (ds_odrInfo.getModifiedIndex().length || ta_rmk2.getValue() != "") {
        ds_odrInfo.setCellData(0, "rmk", ta_rmk1.getValue() + " " + ta_rmk2.getValue());
        ds_odrInfo.setCellData(0, "regBranCd", scwin.lobranCd);
        dma_odrInfo.setEmptyValue();
        await scwin.submitExcute(sbm_registM);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더정보"]); //@은(는) 변경된 사항이 없습니다.
    }
}

//디테일 저장
scwin.f_updateD = function () {
    gr_cntrInfo.setReadOnly("grid", false);

    ds_cntrInfo.setRowPosition(0);
    let rowVal = ds_cntrInfo.getRowPosition();
    scwin.f_setGridCntrInfoByWrkRslts(rowVal);
    $c.gus.cfEnableObjects([btn_saveD]);
    $c.gus.cfDisableObjects([btn_updateD]);
}

scwin.f_saveD = async function () {
    if (ds_cntrInfo.getModifiedIndex().length) {
        // tr_registD.KeyValue = "JSP(I:IN_DS1=ds_odrInfo,I:IN_DS2=ds_cntrInfo)";
        // tr_registD.Action = "/tn.sd.odrmgnt.cntrodrreg.UpdateContainerInformationCMD.do";
        await scwin.submitExcute(sbm_registD);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너목록"]); //@은(는) 변경된 사항이 없습니다.
    }
}


// 사용하지 않는 함수인듯.
//그리드활성/비활성화
scwin.f_setActiveGrid = function (gubun) {
    let val;
    switch (gubun) {
        case "E": // 활성
            val = false;
            break;
        case "D": // 비활성
            val = true;
            break;
        default:
            break;
    }
    gr_cntrInfo.setReadOnly("grid", val);
}

