}

//그리드에서 팝업오픈하기전 작업(코드와 코드명이 있는 경우)
scwin.f_openPopUpGridBefore = async function (ds, row, cdColid, nmColid, olddata, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    //  && ds_cntrInfo.getCellData(row, cdColid) != olddata
    if (ds_cntrInfo.getCellData(row, cdColid) != "") {
        ds_cntrInfo.setCellData(row, nmColid, "");
        await scwin.f_openPopUpGrid(ds_cntrInfo, row, cdColid, nmColid, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF);
    } else if (ds_cntrInfo.getCellData(row, cdColid) == "") {
        ds_cntrInfo.setCellData(row, cdColid, "");
        ds_cntrInfo.setCellData(row, nmColid, "");
    }
}

//그리드 팝업
// 1.컨테이너목록(From(출발지)) : 작업장구분코드가 지역인 경우, 에러메시지 띄우고 ''처리하기
scwin.f_openPopUpGrid = async function (ds, row, cdColid, nmColid, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let pCode = "";
    let pName = "";
    let pWtitleSearch = null;
    let pWhere = null;
    let rtnList = new Array();

    let pSelectID = ""

    pCode = ds.getCellData(row, cdColid);

    switch (gubun) {
        case 1:   //컨테이너목록 - TO(도착지)
            pSelectID = "retrieveWrkPlInfo";
            pWtitleSearch = "작업장,코드,코드명";
            break;

        case 2:   //컨테이너목록 - 현위치
            pSelectID = "retrieveWrkPlInfo";
            pWtitleSearch = "현위치, 코드, 코드명";
            break;

        case 3:   //컨테이너목록 - 항구코드
            pSelectID = "retrievePortInfo";
            pWtitleSearch = "항구, 코드, 코드명";
            break;

        case 4:   //컨테이너목록 - 항구코드
            pSelectID = "retrievePortInfo";
            pWtitleSearch = "목적항구, 코드, 코드명";
            break;

        case 5:   //컨테이너목록 - From(출발지)
            pSelectID = "retrieveWrkPlInfo";
            pWtitleSearch = "작업장,코드,코드명";
            pWhere = "";
            break;

        default:
            break;
    }

    gridComcode.setSelectId(pSelectID);

    rtnList = gridComcode.cfCommonPopUpAsync(
        (rtnList) => {
            switch (gubun) {
                case 3:
                    $c.gus.cfSetGridReturnValue(rtnList, ds, row, cdColid, nmColid);
                    ds_cntrInfo.setCellData(row, "destPortCd", ds_cntrInfo.getCellData(row, "portCd"));
                    ds_cntrInfo.setCellData(row, "destPortNm", ds_cntrInfo.getCellData(row, "portNm"));
                    break;
                default:
                    $c.gus.cfSetGridReturnValue(rtnList, ds, row, cdColid, nmColid);
                    break;
            }
        },

        // pSelectID,						//pSelectID   
        pCode,							//pCode
        pName,							//pName
        pWinCloseTF,					//pWinCloseTF
        null,							//pDispCnt
        null,							//pTitle
        null,							//pWidth
        null,							//pHidden
        pWhere,							//pWhere
        null,							//pW
        null,							//pH
        null,							//pTop
        null,							//pLeft
        null,							//pExistTF - 중복체크여부	("F")
        pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
        pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        pNoDataCloseTF,                 //Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
        null
    );

    // $c.gus.cfSetGridReturnValue(rtnList, ds, row, cdColid, nmColid);
}

scwin.f_setTemperDryByRFCntr = function (ds, gr, row) {
    if (row > 0) {
        //품명 또는 컨테이너  type이 RF인 경우, 온도 또는 dry 체크
        let type = ds.getCellData(row, "cntrTypCd");
        let temper = ds.getCellData(row, "temper");
        let dryYn = ds.getCellData(row, "dryYn");
        let temperBool;
        let dryYnBool;

        //오더별 체크
        if (["RF", "RH"].includes(type)) {
            if (!$c.gus.cfIsNull(temper) && dryYn == "0") {
                temperBool = false
                dryYnBool = true
            } else if ($c.gus.cfIsNull(temper) && dryYn == "1") {
                temperBool = true
                dryYnBool = false
            } else {
                temperBool = false
                dryYnBool = false
            }

            gr.setCellReadOnly(row, 'temper', temperBool);
            gr.setCellReadOnly(row, 'dryYn', dryYnBool);

        } else {
            ds.setCellData(row, "temper", "");
            ds.setCellData(row, "dryYn", 0);
            gr.setCellReadOnly(row, 'temper', true);
            gr.setCellReadOnly(row, 'dryYn', true);
        }
    }
}

scwin.f_setGridCntrInfoByWrkRslts = async function (row) {
    let cntrInfoRows = ds_cntrInfo.getTotalRow();
    if (cntrInfoRows > 0 && btn_updateD.getDisabled() == false) {
        let confirmVal = await scwin.f_chkResultsConfirmation("CNTR_ROW")

        if (confirmVal) { //실적발생한 경우
            gr_cntrInfo.setReadOnly("grid", true);
        } else { //실적발생하지 않은 경우
            gr_cntrInfo.setReadOnly("grid", false);
            if (ds_cntrInfo.getRowStatusValue(row) == 1) { //insert인 경우			
                //오더별 세팅
                if (scwin.odrKndCd == "C3" ||
                    scwin.odrKndCd == "CW") { //수출본선, 수출TS			
                    scwin.f_setCntrGridForSizTypFE("EC");
                } else if ((scwin.odrKndCd == "C4" && selfClsCd == "LS") //수출일반(자가영업)
                    || scwin.odrKndCd == "C5"	       //on-hire
                    || scwin.odrKndCd == "C6"	       //off-hire
                    || scwin.odrKndCd == "C7"  //empty position
                    || (scwin.odrKndCd == "CT" && odrCtrlClsCd == "2")
                ) {
                    if ((scwin.odrKndCd == "C7" && selfClsCd != "LS")	//empty position(자가영업이 아닌경우)
                        || scwin.odrKndCd == "C6"   //off-hire
                    ) {
                        scwin.f_setCntrGridForSizTypFE("EC");
                    } else {
                        scwin.f_setCntrGridForSizTypFE("E");
                    }
                } else {
                    scwin.f_setCntrGridForSizTypFE("D");
                }
            } else {

                //현재 컨테이너번호 또는 org컨테이너번호가 미지정인 경우(update인 경우)
                if ($c.gus.cfIsNull(ds_cntrInfo.getCellData(row, "cntrNo")) || $c.gus.cfIsNull(ds_cntrInfo.getCellData(row, "cntrNo"))) {
                    //오더별 세팅
                    if (scwin.odrKndCd == "C3" ||
                        scwin.odrKndCd == "CW") { //수출본선, 수출TS			
                        scwin.f_setCntrGridForSizTypFE("EC");
                    } else if ((scwin.odrKndCd == "C4" && selfClsCd == "LS") //수출일반(자가영업)
                        || scwin.odrKndCd == "C5"		   //on-hire
                        || scwin.odrKndCd == "C6"	       //off-hire
                        || scwin.odrKndCd == "C7"  //empty position
                    ) {
                        if (scwin.odrKndCd == "C7" && selfClsCd != "LS"	//empty position(자가영업이 아닌경우)
                            || scwin.odrKndCd == "C6"   //off-hire
                        ) {
                            scwin.f_setCntrGridForSizTypFE("EC");
                        } else {
                            scwin.f_setCntrGridForSizTypFE("E");
                        }
                    } else {
                        scwin.f_setCntrGridForSizTypFE("D");
                    }
                } else {
                    scwin.f_setCntrGridForSizTypFE("D");
                }
            }
            //수출일반인 경우  - 컨테이너 type이 RF인 경우, 온도 또는 dry 체크
            scwin.f_setTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, row);
        }
    }
}


scwin.f_setCntrGridForSizTypFE = function (gubun) {

    let cntrSizCd;
    let cntrTypCd;
    let mgnfullEmptyClsCdtNo;

    switch (gubun) {
        case "E":
            cntrSizCd = false
            cntrTypCd = false
            mgnfullEmptyClsCdtNo = false
            break;
        case "D":
            cntrSizCd = true
            cntrTypCd = true
            mgnfullEmptyClsCdtNo = true
            break;
        case "EC": //수출본선인 경우, F/E만 수정가능
            cntrSizCd = true
            cntrTypCd = true
            mgnfullEmptyClsCdtNo = false
            break;
        default:
            break;
    }

    gr_cntrInfo.setColumnReadOnly('cntrSizCd', cntrSizCd)
    gr_cntrInfo.setColumnReadOnly('cntrTypCd', cntrTypCd)
    gr_cntrInfo.setColumnReadOnly('mgnfullEmptyClsCdtNo', mgnfullEmptyClsCdtNo)
}


//실적 발생여부를 확인
scwin.f_chkResultsConfirmation = function (gubun) {
    let cntrTotalRows = ds_cntrInfo.getTotalRow();
    if (gubun == "CNTR_ROW") {
        if (cntrTotalRows > 0) {
            if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.rowPosition ?? 0, "wrkRsltsNo"))) return true; // 실적이 존재하는 경우
        }
    } else {
        if (cntrTotalRows > 0) {
            for (i = 0; i < cntrTotalRows; i++) {
                if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo"))) return true; // 실적이 존재하는 경우
            }
        }
    }
    return false;	// 실적이 존재하지 않는 경우
}


