                ["portCd", "impCntrWrkKndCd", "impMgsetYn", "dcsnYn", "destPortCd"
                    , "wt", "temper", "dryYn"],
                "show", "true");
            scwin.f_displayGridColumn(gr_excel,
                ["dptWrkPlCd", "arvWrkPlCd", "currPosCd", "xrayLupTrgtYn", "leaseYn", "socYn",
