    }
}

// to-do
scwin.f_displayGridColumn = function (gridObject, columnArray, feature, value) {
    for (var i in columnArray) {
        if (columnArray[i] != null) {
            gridObject.setColumnVisible(columnArray[i], value);
        }
    }
}

scwin.f_openPopUpGrid2 = function (ds, row, cdColid, nmColid, gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF, ds2) {

    let pCode = "";
    let pName = "";
    let pWtitleSearch = null;
    let pWhere = null;
    let rtnList = new Array();

    pCode = ds.getCellData(row, cdColid);

    if (gubun == 3) { //컨테이너목록 - 항구코드
        pSelectID = "retrievePortInfo";
        pWtitleSearch = "항구, 코드, 코드명";

    } else if (gubun == 4) { //컨테이너목록 - 항구코드
        pSelectID = "retrievePortInfo";
        pWtitleSearch = "목적항구, 코드, 코드명";
    }
    udc_select.setSelectId(pSelectID)
    udc_select.cfCommonPopUpAsync(
        (rtnList) => {
            $c.gus.cfSetGridReturnValue(rtnList, ds2, row, cdColid, nmColid);
        }
        ,						//pSelectID   
        pCode,							//pCode
        pName,							//pName
        pWinCloseTF,					//pWinCloseTF
        null,							//pDispCnt
        null,							//pTitle
        null,							//pWidth
        null,							//pHidden
        pWhere,							//pWhere
        null,							//pW
        null,							//pH
        null,							//pTop
        null,							//pLeft
        null,							//pExistTF - 중복체크여부	("F")
        pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
        pWtitleSearch,					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        pNoDataCloseTF,                 //Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
        null
    );

}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch, pNoDataCloseTF, row) {
    // 선언부
    let rtnList = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun) {
        case 1:
            udc_portCd.cfCommonPopUpAsync(
                (rtnList) => {
                    if (rtnList != null && rtnList[0] != 'N/A') {
                        ds_cntrInfo.setCellData(row, "portCd", rtnList[0]); //작업장코드
                        ds_cntrInfo.setCellData(row, "portNm", rtnList[1]); //작업장명
                        if (ds_cntrInfo.getCellData(row, "portCd") == 'undefined') {
                            ds_cntrInfo.setCellData(row, "portNm", '');
                        }
                    } else {
                        ds_cntrInfo.setCellData(row, "portCd", '');
                        ds_cntrInfo.setCellData(row, "portNm", '');
                    }
                }

                // XML상의 SELECT ID	
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 ㅇ도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch				// 전체검색허용여부	("F")
                , "항구, 코드, 코드명"	// POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                , pNoDataCloseTF
            );

            break;

        case 2:
            udc_portInfo.cfCommonPopUpAsync(
                (rtnList) => {
                    if (rtnList != null && rtnList[0] != 'N/A') {
                        ds_cntrInfo.setCellData(row, "destPortCd", rtnList[0]); //작업장코드
                        ds_cntrInfo.setCellData(row, "destPortNm", rtnList[1]); //작업장명
                        if (ds_cntrInfo.getCellData(row, "destPortCd") == 'undefined') {
                            ds_cntrInfo.setCellData(row, "destPortNm", '');
                        }
                    } else {
                        ds_cntrInfo.setCellData(row, "destPortCd", '');
                        ds_cntrInfo.setCellData(row, "destPortNm", '');
                    }
                }

                // XML상의 SELECT ID	
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch				// 전체검색허용여부	("F")
                , "목적항구, 코드, 코드명"	// POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                , pNoDataCloseTF
            );
            break;

    }
}

scwin.f_Upload = async function () {
    if (udc_grd.getUpExt() == "1") { // xlsx, csv 선택값
        var options = {
            // headerExist: 1,
            fileName: "컨테이너목록",
            startRowIndex: 1,
            startColumnIndex: 0,
            type: 1,
            status: "C",
            hidden: "0"
        }
        await $c.data.uploadGridViewCSV(gr_excel, options); // CSV를 선택하였을 경우

    } else {

        let odrKndCd2 = ed_odrNo.getValue().substring(1, 3);

        if (!(odrKndCd2 == "C1" || odrKndCd2 == "CT")) {
            await $c.win.alert("C1오더, CT오더만 업로드 가능합니다. ");
            return;
        }

        var options = {
            // headerExist: 1,
            startRowIndex: 1,
            type: 1,
            status: "C"
        }
        await $c.data.uploadGridViewExcel(gr_cntrInfo, options); // XLSX를 선택하였을 경우

    }

    // //파일업로드용 hide 그리드 새로 생성
    // await udc_grd.uploadGridViewExcel(gr_cntrInfo, options);
}



