scwin.f_Excel = async function (varGrNm) {
    // let grid = document.getElementById(varGrNm);
    let grid = gr_cntrInfo

    if ($c.gus.cfIsNull(grid)) return;

    let excelDown = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")

    if (excelDown) {
        // cfGridToExcel(eval(varGrNm), "컨테이너목록", "컨테이너목록.xls", 4 + 8 + 16);

        const grdObj = grid;
        const infoArr = [];
        const options = {
            fileName: "컨테이너목록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: "컨테이너목록"
        };
        $c.data.downloadGridViewExcel(grdObj, options, infoArr);
    }
}



//-------------------------------------------------------------------------
// input 파일 확장자를 검사한다. // 호출하는곳이 없음
//-------------------------------------------------------------------------
scwin.f_CheckFileExt = function (ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    elen = ext.length;
    flen = path.length;
    return (ext == path.substring((flen - elen), flen));
}

// TRANSACTION EVENT : tr_retrieve에서 OnSuccess이벤트 발생시
// for=tr_retrieve event=OnSuccess()
scwin.sbm_retrieve_submitdone = async function (e) {


    ta_rmk2.setValue("");
    scwin.odrKndCd = ds_odrInfo.getCellData(0, "odrKndCd");
    scwin.f_setInterfaceByOdr2(scwin.odrKndCd, scwin.impExpClsCd);
    $c.gus.cfDisableObjects([tbl_odrInfoArea, tbl_rmk, tbl_odrInfoArea2]);
    $c.gus.cfDisableObjects([btn_saveM, btn_saveD, btn_deleteD]);
    $c.gus.cfEnableObjects([btn_updateM, btn_updateD]);

    gr_cntrInfo.setReadOnly("grid", true);

    let rowData = ds_odrInfo.getAllJSON()[0];

    dma_odrInfo.setJSON(rowData);
    ed_ctrtClntNo.setValue(rowData.ctrtClntNo);
    ed_ctrtClntNm.setValue(rowData.ctrtClntNm);
    ed_ctrtNo.setValue(rowData.ctrtNo);
    ed_bilgClntNo.setValue(rowData.bilgClntNo);
    // ed_bilgClntNm.setValue(rowData.bilgClntNm);
    ed_lineCd.setValue(rowData.lineCd);
    ed_lineNm.setValue(rowData.lineNm);
    ed_vsslCd.setValue(rowData.vsslCd);
    ed_portcnt.setValue(rowData.portcnt);
