scwin.f_Import = async function (value) {

    var odrKndCd2 = ed_odrNo.getValue().substring(1, 3);

    if (!(odrKndCd2 == "C1" || odrKndCd2 == "CT")) {
        await $c.win.alert("C1오더, CT오더만 업로드 가능합니다. ");
        return;
    }

    var cntrNoSeq = 0;
    var portSeq = 0;
    var destPortSeq = 0;
    var temperSeq = 0;
    var wtSeq = 0;

    //오더종류에 따라 컨테이너 목록 컬럼이 변경되므로..
    if (odrKndCd2 == "C1") {
        cntrNoSeq = $c.num.parseInt(3);
        portSeq = 9;
        destPortSeq = 10;
        temperSeq = 16;
        wtSeq = 18;
    }
    else if (odrKndCd2 == "CT") {
        cntrNoSeq = 3;
        portSeq = 10;
        destPortSeq = 11;
        temperSeq = 13;
        wtSeq = 15;
    }

    for (var i = 0; i < ds_excel.getRowCount(); i++) {
        if (ds_excel.getCellData(i, cntrNoSeq).trim() == ds_cntrInfo.getCellData(i, "cntrNo")) {
            await scwin.f_openCommonPopUp(1, ds_excel.getCellData(i, portSeq).trim(), '', 'T', 'T', 'T', i);
            await scwin.f_openCommonPopUp(2, ds_excel.getCellData(i, destPortSeq).trim(), '', 'T', 'T', 'T', i);
            ds_cntrInfo.setCellData(i, "temper", ds_excel.getCellData(i, temperSeq).trim());
            ds_cntrInfo.setCellData(i, "wt", ds_excel.getCellData(i, wtSeq).trim());
        }

        if (i == ds_excel.getTotalRow() - 1) {
            await $c.win.alert("파일업로드가 정상적으로 완료하였습니다. 저장하십시오. ");
        }

    }

    totalRows.setValue(ds_cntrInfo.getRowCount());
    // cfShowTotalRows(totalRows, ds_cntrInfo.get);
    // gr_cntrInfo.ReDraw = "true";
};

